/*!40000 ALTER TABLE `sys_notice` DISABLE KEYS */;
INSERT INTO `sys_notice` VALUES (1,'聊天室 相关公告','2',_binary '<p>目前<strong>仅开放表情功能</strong>，其他功能敬请期待；开启<strong>“智能小助理”</strong>功能，可<strong>调用AI回答</strong>您的问题！</p>','0','ry','2024-01-30 10:01:32','',NULL,NULL),(2,'BI智能分析','2',_binary '<p>1、通过<strong>分析目标</strong>和<strong>Excel数据</strong>，使用AIGC生成<strong>①Echarts的JSON图表</strong>、<strong>②分析结论</strong>，返回前端进行展示。</p><p>2、BI智能分析分为<strong>阻塞模式</strong>和<strong>异步模式</strong>（建议使用异步模式，等待约30s后可到”<strong>我的图表</strong>“中进行查看）。</p>','0','ry','2024-01-30 10:00:32','ry','2024-01-30 10:05:15',NULL),(3,'聚合搜索相关公告','2',_binary '<ol><li><span style=\"color: rgb(0, 0, 0);\">聚合搜索文章时，是</span><strong style=\"color: rgb(0, 0, 0);\">本系统</strong><span style=\"color: rgb(0, 0, 0);\">中的文章，开始是本系统热度</span><strong style=\"color: rgb(0, 0, 0);\">Top5</strong><span style=\"color: rgb(0, 0, 0);\">的标题；</span></li><li><span style=\"color: rgb(0, 0, 0);\">文章搜索采用ElasticSearch技术；图片则是网络图片；</span></li><li><span style=\"color: rgb(0, 0, 0);\"><span class=\"ql-cursor\">﻿</span>后续将去掉用户搜索，添加其他功能例如视频等！</span></li></ol>','0','admin','2024-01-30 09:43:15','',NULL,NULL);
/*!40000 ALTER TABLE `sys_notice` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `sys_oper_log`
--

DROP TABLE IF EXISTS `sys_oper_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_oper_log` (
  `oper_id` bigint NOT NULL AUTO_INCREMENT COMMENT '日志主键',
  `title` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '模块标题',
  `business_type` int DEFAULT '0' COMMENT '业务类型（0其它 1新增 2修改 3删除）',
  `method` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '方法名称',
  `request_method` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '请求方式',
  `operator_type` int DEFAULT '0' COMMENT '操作类别（0其它 1后台用户 2手机端用户）',
  `oper_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '操作人员',
  `dept_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '部门名称',
  `oper_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '请求URL',
  `oper_ip` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '主机地址',
  `oper_location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '操作地点',
  `oper_param` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '请求参数',
  `json_result` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '返回参数',
  `status` int DEFAULT '0' COMMENT '操作状态（0正常 1异常）',
  `error_msg` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '错误消息',
  `oper_time` datetime DEFAULT NULL COMMENT '操作时间',
  `cost_time` bigint DEFAULT '0' COMMENT '消耗时间',
  PRIMARY KEY (`oper_id`) USING BTREE,
  KEY `idx_sys_oper_log_bt` (`business_type`) USING BTREE,
  KEY `idx_sys_oper_log_s` (`status`) USING BTREE,
  KEY `idx_sys_oper_log_ot` (`oper_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=172 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='操作日志记录';
/*!40101 SET character_set_client = @saved_cs_client */;

