.web.controller.system.SysNoticeController.remove()','DELETE',1,'ry',NULL,'/system/notice/2','127.0.0.1','内网IP','{}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2024-01-30 09:56:40',15),(128,'通知公告',1,'com.ruoyi.web.controller.system.SysNoticeController.add()','POST',1,'ry',NULL,'/system/notice','127.0.0.1','内网IP','{\"createBy\":\"ry\",\"noticeContent\":\"<p>1、介绍：</p><p>\\t通过分析目标和数据，使用AIGC生产Echarts的①JSON图表、②分析结论，返回前端进行展示。</p><p>\\tBI智能分析分为<strong>阻塞模式</strong>和<strong>异步模式</strong>（建议使用异步模式，等待约30s后可到”我的图表“中进行查看）。</p><p>2、使用方法：</p><p>\\t输入您要对数据分析的需求，并上传一个包含excel的数据，即可调用AI帮您生成一个图表和分析结论！</p>\",\"noticeTitle\":\"BI智能分析\",\"noticeType\":\"2\",\"params\":{},\"status\":\"0\"}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2024-01-30 10:00:33',21),(129,'通知公告',1,'com.ruoyi.web.controller.system.SysNoticeController.add()','POST',1,'ry',NULL,'/system/notice','127.0.0.1','内网IP','{\"createBy\":\"ry\",\"noticeContent\":\"<p>目前<strong>仅开放表情功能</strong>，其他功能敬请期待；开启<strong>“智能小助理”</strong>功能，可<strong>调用AI回答</strong>您的问题！</p>\",\"noticeTitle\":\"聊天室 相关公告\",\"noticeType\":\"2\",\"params\":{},\"status\":\"0\"}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2024-01-30 10:01:32',18),(130,'通知公告',2,'com.ruoyi.web.controller.system.SysNoticeController.edit()','PUT',1,'ry',NULL,'/system/notice','127.0.0.1','内网IP','{\"createBy\":\"ry\",\"createTime\":\"2024-01-30 10:00:32\",\"noticeContent\":\"<p>1、通过<strong>分析目标</strong>和<strong>Excel数据</strong>，使用AIGC生成<strong>①Echarts的JSON图表</strong>、<strong>②分析结论</strong>，返回前端进行展示。</p><p>2、BI智能分析分为<strong>阻塞模式</strong>和<strong>异步模式</strong>（建议使用异步模式，等待约30s后可到”<strong>我的图表</strong>“中进行查看）。</p>\",\"noticeId\":11,\"noticeTitle\":\"BI智能分析\",\"noticeType\":\"2\",\"params\":{},\"status\":\"0\",\"updateBy\":\"ry\"}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2024-01-30 10:05:15',20),(131,'在线用户',7,'com.ruoyi.web.controller.monitor.SysUserOnlineController.forceLogout()','DELETE',1,'gqc',NULL,'/monitor/online/5ec3b545-7ec6-4824-9b64-301897dcec17','119.164.128.151','XX XX','{}',